final:
module SR_FlipFlop (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q
);
    always @(posedge clk) begin
        if (S && ~R) 
            obf_Q <= 1;  // Set
        else if (~S && R) 
            obf_Q <= 0;  // Reset
        // If S=0 and R=0, obf_Q retains its previous state
        // If S=1 and R=1, obf_Q retains its previous state
    end
endmodule
